     7→const PROFILE_SECTION_IDS = ["stats", "bio", "joined_date"];
     8→const PROFILE_SECTION_SIZES = ["sm", "md", "lg"];
     9→
    10→const sanitizeProfileLayout = (layout) => {
    11→    if (!layout || typeof layout !== "object") {
    12→        return null;
    13→    }
    14→
    15→    const incomingSections = Array.isArray(layout.sections) ? layout.sections : [];
    16→    const normalizedSections = [];
    17→
    18→    incomingSections.forEach((section) => {
    19→        if (!PROFILE_SECTION_IDS.includes(section?.id)) {
    20→            return;
    21→        }
    22→        if (normalizedSections.find((item) => item.id === section.id)) {
    23→            return;
    24→        }
    25→
    26→        normalizedSections.push({
    27→            id: section.id,
    28→            visible: section.visible !== false,
    29→            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : "md",
    30→            x: Number.isFinite(section?.x) ? Math.max(0, section.x) : null,
    31→            y: Number.isFinite(section?.y) ? Math.max(0, section.y) : null,
    32→            content_width: Number.isFinite(section?.content_width) ? Math.max(120, section.content_width) : null,
    33→            content_height: Number.isFinite(section?.content_height) ? Math.max(40, section.content_height) : null,
    34→        });
    35→    });
    36→
    37→    PROFILE_SECTION_IDS.forEach((sectionId) => {
    38→        if (normalizedSections.find((section) => section.id === sectionId)) {
    39→            return;
    40→        }
    41→        normalizedSections.push({
    42→            id: sectionId,
    43→            visible: true,
    44→            size: "md",
    45→            x: null,
    46→            y: null,
    47→            content_width: null,
    48→            content_height: null,
    49→        });
    50→    });
    51→
    52→    return {
    53→        version: layout?.version || 1,
    54→        preset: layout?.preset || "classic",
    55→        spacing: layout?.spacing || "md",
    56→        radius: layout?.radius || "lg",
    57→        sections: normalizedSections,
    58→    };
    59→};
