   175→router.get('/getNotifications', async(req, res) =>{
   176→    const {before, limit} = req.query;
   177→
   178→    const token = req.headers?.authorization?.split(' ')[1];
   179→    if(!token){
   180→        console.error('not authorized')
   181→        return res.status(400).json({error:'not authorized'})
   182→    }
   183→
   184→    const {data: authData, error: errorAuthData} = await supabase.auth.getUser(token);
   185→
   186→    if(errorAuthData){
   187→        console.error('error:', errorAuthData.message);
   188→        return res.status(500).json({error: 'error on checking authorization'})
   189→    }
   190→
   191→    const userId = authData?.user?.id;
   192→
   193→    // Fetch a generous amount from both tables, then merge and paginate
   194→    const fetchLimit = parseInt(limit) + 1;
   195→
   196→    let journalQuery = supabase
   197→    .from('notifications')
   198→    .select(
   199→        `*,
   200→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
   201→        users!sender_id(name, user_email, image_url, id, badge)
   202→        `
   203→    )
   204→    .eq('receiver_id', userId)
   205→    .order('created_at', {ascending: false})
   206→    .order('id', {ascending: false})
   207→    .limit(fetchLimit)
   208→
   209→    let opinionQuery = supabase
   210→    .from('notification_opinions')
   211→    .select(
   212→        `*,
   213→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
   214→        users!sender_id(name, user_email, image_url, id, badge)
   215→        `
   216→    )
   217→    .eq('receiver_id', userId)
   218→    .order('created_at', {ascending: false})
   219→    .order('id', {ascending: false})
   220→    .limit(fetchLimit)
   221→
   222→    if(before){
   223→        journalQuery = journalQuery.lt('created_at', before);
   224→        opinionQuery = opinionQuery.lt('created_at', before);
   225→    }
   226→
   227→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
   228→
   229→    if(journalResult.error){
   230→        console.error('error while fetching data from notification table:', journalResult.error);
   231→        return res.status(500).json({error: 'error fetching data from notification table'});
   232→    }
   233→    if(opinionResult.error){
   234→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
   235→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
   236→    }
   237→
   238→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
   239→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
   240→
   241→    // Merge and sort by created_at descending
   242→    const merged = [...journalNotifs, ...opinionNotifs]
   243→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
   244→
   245→    // Likes/bookmarks lookup only for journal notifications
   246→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
   247→
   248→    let hasLikedResult = [];
   249→    let hasBookMarkedResult = [];
   250→    if(journalIds.length > 0){
   251→        const [hasLiked, hasBookMarked] = await Promise.all([
   252→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
   253→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
   254→        ]);
   255→
   256→        if(hasLiked.error || hasBookMarked.error){
   257→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
   258→        }
   259→        hasLikedResult = hasLiked.data || [];
   260→        hasBookMarkedResult = hasBookMarked.data || [];
   261→    }
   262→
   263→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
   264→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
   265→
   266→    const formatted = merged.map((notif) => ({
   267→        ...notif,
   268→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
   269→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
   270→    }))
   271→
   272→    const hasMore = formatted.length > parseInt(limit);
   273→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
   274→
   275→    return res.status(200).json(
   276→        {
   277→            hasMore: hasMore,
   278→            data: slicedData,
   279→        }
   280→    )
   281→
   282→})
