    12→        spacing: layout?.spacing || DEFAULT_PROFILE_LAYOUT.spacing,
    13→        radius: layout?.radius || DEFAULT_PROFILE_LAYOUT.radius,
    14→        sections: DEFAULT_PROFILE_LAYOUT.sections.map((section) => ({ ...section })),
    15→    };
    16→
    17→    const incomingSections = Array.isArray(layout?.sections) ? layout.sections : [];
    18→    const normalizedSections = [];
    19→
    20→    incomingSections.forEach((section) => {
    21→        if (!PROFILE_SECTION_IDS.includes(section?.id)) {
    22→            return;
    23→        }
    24→
    25→        if (normalizedSections.find((item) => item.id === section.id)) {
    26→            return;
    27→        }
    28→
    29→        normalizedSections.push({
    30→            id: section.id,
    31→            visible: section.visible !== false,
    32→            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : "md",
    33→            x: Number.isFinite(section?.x)
    34→                ? Math.max(0, section.x)
    35→                : getDefaultSectionPosition(section.id).x,
    36→            y: Number.isFinite(section?.y)
    37→                ? Math.max(0, section.y)
    38→                : getDefaultSectionPosition(section.id).y,
    39→            height: Number.isFinite(section?.height) ? Math.max(72, section.height) : null,
    40→            content_width: Number.isFinite(section?.content_width)
    41→                ? Math.max(120, section.content_width)
    42→                : null,
    43→            content_height: Number.isFinite(section?.content_height)
    44→                ? Math.max(40, section.content_height)
    45→                : null,
    46→        });
    47→    });
    48→
    49→    PROFILE_SECTION_IDS.forEach((sectionId) => {
    50→        if (normalizedSections.find((section) => section.id === sectionId)) {
    51→            return;
    52→        }
    53→
    54→        const defaultSection = DEFAULT_PROFILE_LAYOUT.sections.find(
    55→            (section) => section.id === sectionId
    56→        );
    57→        normalizedSections.push({ ...defaultSection });
    58→    });
    59→
    60→    normalized.sections = normalizedSections;
    61→
    62→    return normalized;
    63→};
