     4→export const getJournalsService = async(limit, userId, before) => {
     5→    if(isNaN(limit) || limit > 20 || limit < 1){
     6→        console.error('limit should be intiger, not below 1 and higher than 20');
     7→        throw {status: 400, error: 'limit should be intiger, not below 1 and higher than 20'};
     8→    }
     9→
    10→    const parsedLimit = parseInt(limit);
    11→
    12→    let query = supabase
    13→    .from('journals')
    14→    .select(`
    15→        *, users(*),
    16→        like_count: likes(count),
    17→        comment_count: comments(count),
    18→        bookmark_count: bookmarks(count)
    19→        `)
    20→    .eq('privacy', 'public')
    21→    .order('created_at', {ascending: false})
    22→    .order('id', {ascending: false})
    23→    .limit(parsedLimit + 1);
    24→
    25→    if(before){
    26→        query = query.lt('created_at', before);
    27→    }
    28→
    29→    const {data, error} = await query;
    30→
    31→    if(error){
    32→        console.error('supabase error while fetching journals:', error.message);
    33→        throw{status: 500, error: 'supabase error while fetching journals'}
    34→    }
    35→
    36→    if(data.length === 0){
    37→        const journalData = {
    38→            data: [],
    39→            hasMore: false
    40→        }
    41→        return journalData
    42→    }
    43→
    44→    // If userId is provided, fetch personalization (likes/bookmarks)
    45→    // Otherwise return journals with has_liked/has_bookmarked defaulting to false
    46→    let userHasLikedSet = new Set();
    47→    let userHasBookmarkedSet = new Set();
    48→
    49→    if(userId){
    50→        const journalIds = data.map((journal) => journal.id);
    51→
    52→        const [userLikes, userBookmarks] = await Promise.all([
    53→            supabase
    54→            .from('likes')
    55→            .select('journal_id')
    56→            .in('journal_id', journalIds)
    57→            .eq('user_id', userId),
    58→
    59→            supabase
    60→            .from('bookmarks')
    61→            .select('journal_id')
    62→            .in('journal_id', journalIds)
    63→            .eq('user_id', userId)
    64→        ]);
    65→
    66→        const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
    67→        const {data: userBookmarksResult, error: errorUserBookmarksResult} = userBookmarks;
    68→
    69→        if(errorUserLikeResult || errorUserBookmarksResult) {
    70→            console.error('supabase error:', errorUserLikeResult?.message || errorUserBookmarksResult?.message);
    71→            throw {status: 500, error: 'supabase error on fetching user likes or user bookmarks'}
    72→        }
    73→
    74→        userHasLikedSet = new Set(userLikesResult?.map((j) => j.journal_id) || []);
    75→        userHasBookmarkedSet = new Set(userBookmarksResult?.map((j) => j.journal_id)|| []);
    76→    }
    77→
    78→    const formattedData = data?.map((journal) => ({
    79→        ...journal,
    80→        has_liked: userHasLikedSet.has(journal.id),
    81→        has_bookmarked: userHasBookmarkedSet.has(journal.id)
    82→    }))
    83→
    84→    const hasMore = data?.length > parsedLimit;
    85→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
    86→
    87→    const journalData = {
    88→        data: slicedData,
    89→        hasMore: hasMore
    90→    }
    91→    return journalData;
    92→}
