   384→    }
   385→    const paresedLimit = parseInt(limit);
   386→    let query = supabase
   387→    .from('bookmarks')
   388→    .select(`*,
   389→        journals(
   390→        id, created_at, user_id, content, title, 
   391→        comment_count: comments(count),
   392→        bookmark_count: bookmarks(count),
   393→
   394→        users(name, user_email, image_url, badge),
   395→
   396→        like_count: likes(count)
   397→        )
   398→        `, {count: 'exact'})
   399→
   400→    .eq('user_id', userId)
   401→    .order('created_at', {ascending: false})
   402→    .order('id', {ascending: false})
   403→    .limit(parseInt(limit) + 1)
   404→
   405→    if(before){
   406→        query = query.lt('created_at', before);
   407→    }
   408→
   409→    const {data: bookMarksData, error: errorBookmarks, count} = await query;
   410→
